// A debounce function delays executing a given function until after a specified wait time has elapsed since the last time it was invoked.
function debounce(func, wait) {
  let timeout;
  return function(...args) {
    clearTimeout(timeout);
    timeout = setTimeout(() => func.apply(this, args), wait);
  };
}

// Example usage:
const log = () => console.log('Called!');
const debouncedLog = debounce(log, 1000);

debouncedLog(); // Will wait 1 second before logging
debouncedLog(); // Resets timer; logs only once 1 second after the last call
